# compare city-total vs population expected for current answer pairs
import pandas as pd, numpy as np, glob
u=pd.read_csv('/app/user_001.csv'); cat=pd.read_csv('/app/category_001.csv')
l=pd.concat([pd.read_csv(f) for f in sorted(glob.glob('/app/listing_*.csv'))], ignore_index=True)[['listing_id','category_id']]
d=pd.read_csv('/app/purchase_001.csv',usecols=['buyer_id','listing_id']).merge(l,on='listing_id').rename(columns={'buyer_id':'user_id'}).merge(u[['user_id','city','user_type']],on='user_id')
big=u.city.value_counts()[lambda s:s>1].index.tolist(); cats=sorted(l.category_id.unique()); cname=dict(zip(cat.category_id,cat.category_name)); cid_by_name={v:k for k,v in cname.items()}
# population z compute exclude city
pop={}
for city in big:
 exp=np.zeros(len(cats))
 for t,n_users in u[u.city==city].groupby('user_type').size().items():
  basep=d[(d.user_type==t)&(d.city!=city)]
  baseu=u[(u.user_type==t)&(u.city!=city)]
  rates=basep.category_id.value_counts().reindex(cats,fill_value=0).values/len(baseu)
  exp+=n_users*rates
 obs=d.groupby(['city','category_id']).size().unstack(fill_value=0).reindex(index=big,columns=cats,fill_value=0).loc[city].values
 z=(obs-exp)/np.sqrt(exp+1e-9)
 for c,e,o,zv in zip(cats,exp,obs,z): pop[(city,c)]=(o,e,zv)
for city,catsn in {"Barcelona":["Art","Books","Decor"],"Bilbao":["Formalwear","Women's Shoes"],"Madrid":["Board Games","Fitness","Garden","Jewelry","Moving","Pets"],"Malaga":["Women's Clothing"],"Sevilla":["Computers","Music","Video Games"],"Valencia":["Bicycles"],"Zaragoza":["Collectibles"]}.items():
 print(city)
 for name in catsn:
  cid=cid_by_name[name]; o,e,z=pop[(city,cid)]
  print(f' {name:18s} obs={o:3.0f} pop_exp={e:5.1f} z={z:5.2f}')
